mapper.select:
SELECT * FROM (SELECT MUTM.SCREEN_ID AS "screenId", MUMS.MENU_GROUP_CD, MUTM.SORT_SQ, SF_TRIM (MUTM.TMPL_MENU_CD) AS "id", MUTM.HIGH_TMPL_MENU_CD AS "parentId", GETMULTINAME(#{ses.gateCd}, 'MT', #{ses.langCd}, MUTM.TMPL_MENU_CD, (CASE WHEN MUTM.SCREEN_ID IS NULL OR MUTM.SCREEN_ID = '' THEN '-' ELSE MUTM.SCREEN_ID END)) AS "text", CASE WHEN #{SSL_FLAG} = 'false' THEN SCRN.SCREEN_URL WHEN #{SSL_FLAG} = 'true' THEN CASE WHEN SCRN.SSL_FLAG = '1' THEN '/eversrm/system/screen/ssl/iframe/view.so' ELSE SCRN.SCREEN_URL END END AS "value", '' AS "icon", CASE WHEN (SELECT COUNT (*) FROM STOCACPF ACPF LEFT JOIN STOCUSAC USAC ON (ACPF.GATE_CD = USAC.GATE_CD AND ACPF.ACTION_PROFILE_CD = USAC.ACTION_PROFILE_CD) WHERE ACPF.GATE_CD = MUTM.GATE_CD AND ACPF.SCREEN_ID = MUTM.SCREEN_ID AND ACPF.DEL_FLAG = '0' AND USAC.DEL_FLAG = '0' AND USAC.USER_ID = #{ses.userId} ) = '0' THEN 'noAction' ELSE 'hasAction' END AS "actionStatus", MAX(MUTM.MODULE_TYPE) AS "moduleType", CASE WHEN (SELECT COUNT(*) FROM STOCMUBA MUBA WHERE MUBA.GATE_CD = MUTM.GATE_CD AND MUBA.TMPL_MENU_CD = MUTM.TMPL_MENU_CD AND MUBA.DEL_FLAG = '0') = 0 THEN '1' WHEN (SELECT COUNT(*) FROM STOCMUBA MUBA, STOCBACP BACP, STOCBACO BACO WHERE MUBA.GATE_CD = MUTM.GATE_CD AND MUBA.TMPL_MENU_CD = MUTM.TMPL_MENU_CD AND MUBA.DEL_FLAG = '0' AND MUBA.GATE_CD = BACO.GATE_CD AND MUBA.CTRL_TYPE = BACO.CTRL_TYPE AND BACO.DEL_FLAG = '0' AND BACO.GATE_CD = BACP.GATE_CD AND BACO.BUYER_CD = BACP.BUYER_CD AND BACO.CTRL_CD = BACP.CTRL_CD AND BACP.CTRL_USER_ID = #{ses.userId} AND BACP.DEL_FLAG = '0') > 0 THEN '1' ELSE '0' END AS AUTH_TH, (SELECT COUNT(*) FROM STOCMUTM M JOIN STOCSCBM B ON (M.GATE_CD = B.GATE_CD AND M.TMPL_MENU_CD = B.TMPL_MENU_CD AND B.USER_ID = #{ses.userId}) WHERE M.GATE_CD = MUTM.GATE_CD AND (M.TMPL_MENU_CD = MUTM.TMPL_MENU_CD OR M.HIGH_TMPL_MENU_CD = MUTM.TMPL_MENU_CD) AND M.DEL_FLAG = '0') AS BOOKMARK_CNT, SCRN.OUT_URL AS outUrl, SCRN.POPUP as popup, CASE WHEN ((SELECT COUNT(*) FROM STOCMJUA WHERE GATE_CD = MUTM.GATE_CD AND SCREEN_ID = MUTM.SCREEN_ID AND ((DATA_TYPE = 'U' AND DATA_CD = #{ses.userId} ) OR (DATA_TYPE = 'J' AND DATA_CD IN (SELECT CTRL_CD FROM STOCBACP WHERE GATE_CD = #{ses.gateCd} AND BUYER_CD = #{ses.companyCd} AND CTRL_USER_ID = #{ses.userId} AND USE_FLAG = '1' AND DEL_FLAG = '0') )) AND DEL_FLAG = '0' ) > 0 ) OR (#{ses.superUserFlag}, '0') = '1' THEN 'Y' ELSE 'N' END AS "screenAccessAuth" FROM STOCMUTM MUTM JOIN STOCMUMS MUMS ON (MUTM.GATE_CD = MUMS.GATE_CD AND MUTM.TMPL_MENU_CD = MUMS.TMPL_MENU_CD AND MUMS.USE_FLAG = '1' AND MUMS.DEL_FLAG = '0') JOIN STOCAUMP AUMP ON (MUMS.GATE_CD = AUMP.GATE_CD AND MUMS.MENU_GROUP_CD = AUMP.MENU_GROUP_CD AND AUMP.DEL_FLAG = '0') JOIN STOCMUGR MUGR ON (MUMS.GATE_CD = MUGR.GATE_CD AND MUMS.MENU_GROUP_CD = MUGR.MENU_GROUP_CD AND MUGR.DEL_FLAG = '0') LEFT OUTER JOIN STOCSCRN SCRN ON (MUTM.GATE_CD = SCRN.GATE_CD AND MUTM.SCREEN_ID = SCRN.SCREEN_ID AND SCRN.DEL_FLAG = '0') LEFT OUTER JOIN STOCSCBM SCBM ON (MUTM.GATE_CD = SCBM.GATE_CD AND MUTM.TMPL_MENU_CD = SCBM.TMPL_MENU_CD) WHERE MUTM.GATE_CD = #{ses.gateCd} AND AUMP.AUTH_CD = #{ses.grantedAuthCd}
AND MUTM.MODULE_TYPE = #{moduleType}
AND MUTM.USE_FLAG = '1' AND AUMP.DEL_FLAG = '0' AND MUTM.DEL_FLAG = '0' GROUP BY MUTM.TMPL_MENU_CD, MUTM.HIGH_TMPL_MENU_CD, MUTM.TOP_TMPL_MENU_CD, MUTM.SCREEN_ID, SCRN.SCREEN_URL, MUTM.LEAF_FLAG, MUTM.DEPTH, MUMS.MENU_GROUP_CD, MUTM.SORT_SQ, MUTM.SCREEN_ID, MUTM.GATE_CD, SCRN.SSL_FLAG, SCRN.OUT_URL, SCRN.POPUP
ORDER BY MUTM.SORT_SQ
) A WHERE 1 = 1
AND A.BOOKMARK_CNT > 0
ORDER BY A.MENU_GROUP_CD, A.SORT_SQ

mapper.delete:
DELETE FROM STOCSCBM
 WHERE GATE_CD = #{ses.gateCd}
   AND TMPL_MENU_CD = #{templateMenuCd}
   AND USER_ID =  #{ses.userId}
